set(USE_SYSTEM_EIGEN OFF)
FetchContent_MakeAvailable(autd3) add_executable(main main.cpp) target_link_libraries(main PRIVATE autd3::autd3 autd3::link::soem) if (CMAKE_GENERATOR MATCHES "Visual Studio") set_property(DIRECTORY ${CMAKE_CURRENT_SOURCE_DIR} PROPERTY VS_STARTUP_PROJECT main)
endif() NOTE: 上記の例では, 依存ライブラリ (Eigen3) を自動的にダウンロードするようになっている. すでにEigen3がインストールされている場合, USE_SYSTEM_EIGENをONにすると, 自動ダウンロードを無効化し, インストール済みのものを使用できる. また, main.cppを以下のようにする. これは単一焦点に150HzのAM変調をかける場合のソースコードである. #include <iostream> #include "autd3.hpp"
#include "autd3/link/soem.hpp" void on_lost(const char* msg) { std::cerr << "Link is lost\n"; std::cerr << msg; exit(-1);
} coro::task<int> main_() { // create and open controller auto autd = co_await autd3::ControllerBuilder() // The argument is the position. // The position is the origin of the device in the global coordinate // system you set. .add_device(autd3::AUTD3(autd3::Vector3::Zero())) .open_with_async(autd3::link::SOEM::builder().with_on_lost(&on_lost)); // check firmware version const auto firm_infos = co_await autd.firmware_infos_async(); std::copy(firm_infos.begin(), firm_infos.end(), std::ostream_iterator<autd3::FirmwareInfo>(std::cout, "\n")); // Silencer is used to quiet down the transducers' noise by passing the // phase/amplitude parameters through a low-pass filter. co_await autd.send_async(autd3::ConfigureSilencer::default_()); // focus is 150.0 mm above array center const autd3::Vector3 focus = autd.geometry().center() + autd3::Vector3(0.0, 0.0, 150.0); autd3::gain::Focus g(focus); // Amplitude Modulation of 150 Hz sine wave autd3::modulation::Sine m(150); // send data co_await autd.send_async(m, g); std::cout << "press enter to finish..." << std::endl; std::cin.ignore(); // close controller co_await autd.close_async(); co_return 0;
} int main() try { return sync_wait(main_()); } catch (std::exception& ex) { std::cerr << ex.what() << std::endl;
} NOTE: macOSでは, _asyncがついた関数がサポートされていないため, _asyncのつかない同期版の関数を使用する必要がある. 次に, CMakeでビルドする. mkdir build
