ライブラリでは自前のGainを作成することができる. ここでは, Focusと同じように単一焦点を生成するFocalPointを実際に定義してみることにする. # extern crate autd3;
# extern crate autd3_driver;
use std::collections::HashMap;
use autd3::{ derive::Gain, prelude::*,
};
use autd3_driver::derive::prelude::*; #[derive(Gain)]
pub struct FocalPoint { position: Vector3,
} impl FocalPoint { pub fn new(position: Vector3) -> Self { Self {position} }
} impl Gain for FocalPoint { fn calc(&self, geometry: &Geometry, filter: GainFilter) -> Result<HashMap<usize, Vec<Drive>>, AUTDInternalError> { Ok(Self::transform(geometry, filter, |dev, tr| Drive { phase: Phase::from_rad((tr.position() - self.position).norm() * tr.wavelength(dev.sound_speed)), intensity: EmitIntensity::MAX, })) }
}
# fn main() { # }
# #include "autd3.hpp" class FocalPoint final : public autd3::Gain { public: explicit FocalPoint(autd3::Vector3 point) : _point(std::move(point)) {} std::unordered_map<size_t, std::vector<autd3::Drive>> calc( const autd3::Geometry& geometry) const override { return autd3::Gain::transform( geometry, [&](const auto& dev, const auto& tr) { const auto phase = (tr.position() - _point).norm() * tr.wavelength(dev.sound_speed()); return autd3::Drive{autd3::Phase::from_rad(phase), autd3::EmitIntensity::maximum()}; }); } private: autd3::Vector3 _point;
}; public class FocalPoint : Gain
{ private readonly Vector3d _point; public FocalPoint(Vector3d point) { _point = point; } public override Dictionary<int, Drive[]> Calc(Geometry geometry) { return Transform(geometry, (dev, tr) => { var tp = tr.Position; var dist = (tp - _point).L2Norm; var phase = dist * tr.Wavenumber(dev.SoundSpeed); return new Drive { Phase = Phase.FromRad(phase), Intensity = EmitIntensity.Max }; }); }
} import numpy as np
from pyautd3 import Drive, EmitIntensity, Geometry, Phase
from pyautd3.gain import Gain class Focus(Gain): def __init__(self, point): self.point = np.array(point) def calc(self, geometry: Geometry) -> dict[int, np.ndarray]: return Gain._transform( geometry, lambda dev, tr: Drive( Phase.from_rad( np.linalg.norm(tr.position - self.point) * tr.wavenumber(dev.sound_speed) ), EmitIntensity.maximum(), ), ) send関数はGain型を継承したクラスを引数に取ることができる. そのため, Gain型を継承をしておく. send関数内部ではGeometryを引数にしたcalcメソッドが呼ばれ, その返り値の振幅/位相データが使用される. そのため, このcalcメソッド内で位相/振幅の計算を行えば良い. calcの返り値は, デバイスのインデックスをキー, そのデバイスの振幅位相データベクトルを値とするHashMapである.

