Modulationも独自のものを作成することができる. ここでは, 周期中のある一瞬だけ出力するBurstを作ってみる [1] . 以下が, このBurstのサンプルである. # extern crate autd3;
# extern crate tokio;
# extern crate autd3_driver;
use autd3::{ derive::Modulation,
};
use autd3_driver::derive::prelude::*; #[derive(Modulation)]
pub struct Burst { config: SamplingConfiguration,
} impl Burst { pub fn new() -> Self { Self { config: SamplingConfiguration::from_frequency(4e3).unwrap() } }
} impl Modulation for Burst { fn calc(&self) -> Result<Vec<EmitIntensity>, AUTDInternalError> { Ok((0..4000) .map(|i| if i == 3999 { EmitIntensity::MAX } else { EmitIntensity::MIN }) .collect()) }
}
# fn main() { # } #include "autd3.hpp" class BurstModulation final : public autd3::Modulation { public: std::vector<autd3::EmitIntensity> calc() const override { std::vector buffer(_buf_size, autd3::EmitIntensity::minimum()); buffer[_buf_size - 1] = autd3::EmitIntensity::maximum(); return buffer; } explicit BurstModulation(const size_t buf_size = 4000) noexcept : autd3::Modulation(autd3::SamplingConfiguration::from_frequency(4e3)), _buf_size(buf_size) {} private: size_t _buf_size;
}; public class Burst : Modulation
{ private readonly int _length; public Burst(int length) : base(SamplingConfiguration.FromFrequency(4e3)) { _length = length; } public override EmitIntensity[] Calc() { var buf = Enumerable.Repeat<EmitIntensity>(EmitIntensity.Min, _length).ToArray(); buf[0] = EmitIntensity.Max; return buf; }
} import numpy as np
from pyautd3 import EmitIntensity, SamplingConfiguration
from pyautd3.modulation import Modulation class Burst(Modulation): _length: int def __init__(self, length: int = 4000): super().__init__(SamplingConfiguration.from_frequency(4e3)) self._length = length def calc(self): buf = np.array([EmitIntensity.minimum()] * self._length) buf[0] = EmitIntensity.maximum() return buf ModulationもGainと同じく, send内部でcalcメソッドが呼ばれ, その返り値の変調データが使用される. したがって, このcalcの中で, 変調データを計算すれば良い. SDKにはない.

