# extern crate tokio;
# extern crate autd3_link_soem;
use autd3::prelude::*;
use autd3_link_soem::SOEM; #[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> { // AUTDを操作するControllerの作成 let mut autd = Controller::builder() // 接続しているデバイス情報の登録 // AUTD3::newの引数は位置 // 位置は自分の設定した座標系におけるこのデバイスの位置を指定する // ここでは, デバイスは原点に置かれるする .add_device(AUTD3::new(Vector3::zeros())) // SOEMリンクを使用してControllerをopenする // with_on_lostで指定したコールバックはSOEMがデバイスをロストしたときに呼ばれる .open_with(SOEM::builder().with_on_lost(|msg| { eprintln!("Unrecoverable error occurred: {msg}"); std::process::exit(-1); })).await?; // ファームウェアバージョンのチェック // ここで, v4.0.x以外が表示される場合の動作は保証しない autd.firmware_infos().await?.iter().for_each(|firm_info| { println!("{}", firm_info); }); // 静音化処理を有効化 // なお, デフォルトで有効にされているので, 実際には必要ない // 無効にしたい場合はConfigureSilencer::disable()を送信する autd.send(ConfigureSilencer::default()).await?; // デバイスの中心から直上150mmに焦点 let center = autd.geometry.center() + Vector3::new(0., 0., 150.0 * MILLIMETER); let g = Focus::new(center); // 150Hzサイン波変調 let m = Sine::new(150.); // データの送信 autd.send((m, g)).await?; println!("press enter to quit..."); let mut _s = String::new(); std::io::stdin().read_line(&mut _s)?; // コントローラーを閉じる autd.close().await?; Ok(())
} そして, これを実行する. cargo run --release

